  "target": "router2",
  "needs_fix": true,
  "plan": {
    "problem": "DHCP on router2 is not providing addresses for 172.16.0.0/24, leaving host 172.16.0.12 without an IP (0/25 pings).",
    "fix_summary": "Restart DHCP service, bind the existing R2_LAN pool to GigabitEthernet0/0/0, and clear current DHCP bindings to force lease assignment.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
